trait Interpreter { fn eval(&self, x: i32) -> i32; }

struct Add;
impl Interpreter for Add { fn eval(&self, x: i32) -> i32 { x.checked_add(1).unwrap_or(i32::MAX) } }

fn compute<I: Interpreter>(interp: &I, a: i32, b: i32) {
    let result = interp.eval(a);
    println!("Result: {}
", result);
}

fn main() {
    let add = Add;
    compute(&add, i32::MAX, 1); // This will not panic and instead wrap around
}
